// Extract and validate upload payload
const body = $input.first().json.body || $input.first().json;
const { filename, fileBase64, mimeType } = body;

if (!filename || !fileBase64) {
  throw new Error('Missing filename or fileBase64 in request body');
}

return [{ json: { filename, fileBase64, mimeType: mimeType || 'application/octet-stream' } }];

// Chunk the extracted text and obtain embeddings from Ollama
// Then prepare Qdrant point objects for batch insertion

const { extractedText, id, collection, filename, textLength } = $input.first().json;

if (!extractedText || extractedText.trim().length < 10) {
  // No extractable text (image-based PDF, encrypted, or empty document)
  return [{ json: { docId: id, collection, textChunks: 0, points: [], noText: true } }];
}

const CHUNK_SIZE = 500;
const OVERLAP    = 50;
const EMBED_MODEL = 'nomic-embed-text-v2-moe';
const OLLAMA_URL  = 'http://host.docker.internal:11434/api/embeddings';

// ── Chunk text ──────────────────────────────────────────────────────────────
const chunks = [];
for (let pos = 0; pos < extractedText.length; pos += (CHUNK_SIZE - OVERLAP)) {
  const text = extractedText.slice(pos, pos + CHUNK_SIZE).trim();
  if (text.length >= 20) chunks.push(text);
}

// Cap at 200 chunks to avoid n8n timeouts on huge documents
const cappedChunks = chunks.slice(0, 200);

// textChunks = actual text segments found in the document (always report this)
const textChunks = cappedChunks.length;

// ── Generate embeddings ──────────────────────────────────────────────────────
const points = [];
for (let i = 0; i < cappedChunks.length; i++) {
  try {
    const resp = await fetch(OLLAMA_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ model: EMBED_MODEL, prompt: cappedChunks[i] }),
    });
    const data = await resp.json();
    if (data.embedding && data.embedding.length > 0) {
      points.push({
        id: Date.now() + i,   // unique numeric ID required by Qdrant
        vector: data.embedding,
        payload: {
          text:        cappedChunks[i],
          doc_id:      id,
          filename:    filename,
          chunk_index: i,
        },
      });
    }
  } catch (err) {
    console.error(`[chunk ${i}] embedding error: ${err.message}`);
  }
}

// Return textChunks (text segments found) separately from points (embedded chunks)
return [{ json: { docId: id, collection, textChunks, points } }];

// Decide whether to insert into Qdrant and what status to report
const { points, docId, collection, totalChunks, textChunks, noText } = $input.first().json;

// textChunks = text segments extracted; fall back to totalChunks for backward compat
const chunkCount = (textChunks !== undefined) ? textChunks : (totalChunks || 0);

if (noText) {
  return [{ json: {
    docId, collection, totalChunks: 0, inserted: 0, skip: true,
    statusToSet: 'error',
    errorMsg: 'No extractable text found. The document may be image-based, encrypted, or empty.'
  } }];
}

if (!points || points.length === 0) {
  return [{ json: {
    docId, collection, totalChunks: chunkCount, inserted: 0, skip: true,
    statusToSet: 'error',
    errorMsg: `Text extracted (${chunkCount} segments) but embedding failed. Ensure the embedding model is running in Ollama.`
  } }];
}

return [{ json: {
  docId, collection, totalChunks: chunkCount, points, inserted: points.length,
  statusToSet: 'ready', errorMsg: null
} }];
